const buffer = msg.payload;
const topic = msg.topic;

if (!buffer) {
    msg.payload = { error: 'Invalid parameters' };
    msg.topic = 'lora/out/error';
    return msg;
}

const messageType = buffer.readUInt8(0);
let packet = {};

try {
    if (messageType === 0x01 && buffer.length === 27) {
        const nodeId = buffer.readUInt32LE(1);
        if (nodeId === 0) {
            msg.payload = { error: 'Invalid packet data - nodeId is 0' };
            msg.topic = 'lora/out/error';
            return msg;
        }
        packet = {
            type: 'sensor',
            nodeId: nodeId,
            counter: buffer.readUInt32LE(5),
            uptime: buffer.readUInt32LE(9),
            battery: buffer.readUInt8(13),
            voltage: buffer.readUInt16LE(14),
            analog: [
                buffer.readUInt16LE(16),
                buffer.readUInt16LE(18),
                buffer.readUInt16LE(20),
                buffer.readUInt16LE(22)
            ],
            digital: buffer.readUInt8(24)
        };
        msg.topic = 'lora/out/sensor';
    } else if (messageType === 0x02 && buffer.length === 35) {
        const nodeId = buffer.readUInt32LE(1);
        const latitude = buffer.readFloatLE(16);
        const longitude = buffer.readFloatLE(20);
        if (nodeId === 0 || latitude < -90 || latitude > 90 || longitude < -180 || longitude > 180) {
            msg.payload = { error: 'Invalid packet data' };
            msg.topic = 'lora/out/error';
            return msg;
        }
        packet = {
            type: 'gnss',
            nodeId: nodeId,
            counter: buffer.readUInt32LE(5),
            uptime: buffer.readUInt32LE(9),
            battery: buffer.readUInt8(13),
            voltage: buffer.readUInt16LE(14),
            latitude: latitude,
            longitude: longitude,
            speed: buffer.readFloatLE(24),
            hdop: buffer.readUInt8(28) / 10.0,
            course: buffer.readFloatLE(29)
        };
        msg.topic = 'lora/out/gnss';
    } else {
        msg.payload = { error: `Unknown packet: type=0x${messageType.toString(16).padStart(2, '0').toUpperCase()}, length=${buffer.length}` };
        msg.topic = 'lora/out/error';
        return msg;
    }
} catch (e) {
    msg.payload = { error: `Parsing error: ${e.message}` };
    msg.topic = 'lora/out/error';
    return msg;
}

msg.payload = packet;
return msg;

const payload = msg.payload;
if (!payload || !payload.nodeId) return null;
if (payload.error) return null;

// Query 1: Update device last_seen
// Query 2: Get device + pin configs for threshold checking
// Query 3: Log event

msg.nodeId = payload.nodeId;
msg.sensorData = payload;

// First, update last_seen and get device info with pin configs
msg.query = `
    WITH updated AS (
        UPDATE devices SET last_seen = NOW() WHERE node_id = ${payload.nodeId}
        RETURNING id, node_id, display_name, owner_id
    )
    SELECT
        d.id as device_id,
        d.display_name,
        o.name as owner_name,
        o.email as owner_email,
        o.phone as owner_phone,
        o.notify_via,
        json_agg(DISTINCT jsonb_build_object(
            'pin_index', dp.pin_index,
            'label', dp.label,
            'trigger', dp.trigger,
            'alert_level', dp.alert_level
        )) FILTER (WHERE dp.label != '' AND dp.trigger != 'None') as digital_pins,
        json_agg(DISTINCT jsonb_build_object(
            'pin_index', ap.pin_index,
            'label', ap.label,
            'low_threshold', ap.low_threshold,
            'high_threshold', ap.high_threshold,
            'alert_level', ap.alert_level
        )) FILTER (WHERE ap.label != '' AND ap.alert_level != 'None') as analog_pins
    FROM updated d
    LEFT JOIN owners o ON d.owner_id = o.id
    LEFT JOIN digital_pins dp ON dp.device_id = d.id
    LEFT JOIN analog_pins ap ON ap.device_id = d.id
    GROUP BY d.id, d.display_name, o.name, o.email, o.phone, o.notify_via
`;

return msg;

const rows = msg.payload;
const sensorData = msg.sensorData;

if (!rows || rows.length === 0) {
    node.warn('Device not found for nodeId: ' + msg.nodeId);
    return null;
}

const device = rows[0];
const alerts = [];

// Check digital pins
if (device.digital_pins && sensorData.digital !== undefined) {
    device.digital_pins.forEach(pin => {
        const pinState = (sensorData.digital >> pin.pin_index) & 1;
        if (pin.trigger === 'High' && pinState === 1) {
            alerts.push({
                deviceId: device.device_id,
                ownerName: device.owner_name,
                ownerEmail: device.owner_email,
                notifyVia: device.notify_via,
                deviceName: device.display_name,
                nodeId: msg.nodeId,
                pinLabel: pin.label,
                alertMessage: 'Triggered HIGH',
                alertLevel: pin.alert_level
            });
        } else if (pin.trigger === 'Low' && pinState === 0) {
            alerts.push({
                deviceId: device.device_id,
                ownerName: device.owner_name,
                ownerEmail: device.owner_email,
                notifyVia: device.notify_via,
                deviceName: device.display_name,
                nodeId: msg.nodeId,
                pinLabel: pin.label,
                alertMessage: 'Triggered LOW',
                alertLevel: pin.alert_level
            });
        }
    });
}

// Check analog pins
if (device.analog_pins && sensorData.analog) {
    device.analog_pins.forEach(pin => {
        const value = sensorData.analog[pin.pin_index];
        if (value === undefined) return;
        if (pin.low_threshold !== null && value < pin.low_threshold) {
            alerts.push({
                deviceId: device.device_id,
                ownerName: device.owner_name,
                ownerEmail: device.owner_email,
                notifyVia: device.notify_via,
                deviceName: device.display_name,
                nodeId: msg.nodeId,
                pinLabel: pin.label,
                alertMessage: `Analog value LOW: ${value}`,
                alertLevel: pin.alert_level
            });
        } else if (pin.high_threshold !== null && value > pin.high_threshold) {
            alerts.push({
                deviceId: device.device_id,
                ownerName: device.owner_name,
                ownerEmail: device.owner_email,
                notifyVia: device.notify_via,
                deviceName: device.display_name,
                nodeId: msg.nodeId,
                pinLabel: pin.label,
                alertMessage: `Analog value HIGH: ${value}`,
                alertLevel: pin.alert_level
            });
        }
    });
}

// Log event to DB
const logMsg = {
    query: `INSERT INTO events (device_id, node_id, message_type, payload)
            VALUES (${device.device_id}, ${msg.nodeId}, '${sensorData.type}', '${JSON.stringify(sensorData)}'::jsonb)`,
    payload: ''
};
node.send([null, logMsg]);

// Process alerts
if (alerts.length > 0) {
    alerts.forEach(alert => {
        const alertMsg = {
            query: `INSERT INTO alerts (device_id, pin_label, alert_message, alert_level)
                    VALUES (${alert.deviceId}, '${alert.pinLabel}', '${alert.alertMessage}', '${alert.alertLevel}')
                    ON CONFLICT (device_id, pin_label)
                    DO UPDATE SET alert_message = EXCLUDED.alert_message,
                                 count = alerts.count + 1,
                                 updated_at = NOW()`,
            payload: '',
            alert: alert
        };
        node.send([alertMsg, null]);
    });
} else {
    node.log('No alerts for nodeId: ' + msg.nodeId);
}

return null;

const alert = msg.alert;
if (!alert) return null;

// Rate limit: check if we recently notified for this device+pin
const key = `notified_${alert.deviceId}_${alert.pinLabel.replace(/\s+/g, '_')}`;
const lastNotified = flow.get(key) || 0;
const now = Date.now();
const cooldownMs = 5 * 60 * 1000; // 5 minute cooldown

if (now - lastNotified < cooldownMs) {
    node.log(`Notification suppressed (cooldown): ${alert.pinLabel}`);
    return null;
}
flow.set(key, now);

const transporter = nodemailer.createTransport({
    host: 'smtp.gmail.com',
    port: 465,
    secure: true,
    auth: {
        user: env.get('NOTIFY_EMAIL_USER'),
        pass: env.get('NOTIFY_EMAIL_PASS')
    }
});

const recipient = alert.ownerEmail;
if (!recipient) {
    node.warn('No email for owner: ' + alert.ownerName);
    return null;
}

const subject = `SensorSentinel Alert: ${alert.pinLabel} on ${alert.deviceName}`;
const body = `Alert for ${alert.ownerName}\n\nDevice: ${alert.deviceName}\nSensor: ${alert.pinLabel}\nMessage: ${alert.alertMessage}\nLevel: ${alert.alertLevel}\nTime: ${new Date().toISOString()}`;

transporter.sendMail({
    from: '"SensorSentinel" <' + env.get('NOTIFY_EMAIL_USER') + '>',
    to: recipient,
    subject: subject,
    text: body
}).then(() => {
    node.log('Notification sent to ' + recipient);
}).catch(err => {
    node.error('Notification failed: ' + err.message);
});

return msg;
